import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import "../../styles/AdminMessages.css";

const Messages = ({ auth, setAuth }) => {
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");
  const [selectedMessages, setSelectedMessages] = useState([]);
  const [currentUser, setCurrentUser] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [filter, setFilter] = useState("all");
  const navigate = useNavigate();

  useEffect(() => {
    if (!auth) {
      navigate("/login");
      return;
    }

    const fetchData = async () => {
      try {
        // Get current user
        const userResponse = await fetch("https://localhost:7235/api/auth/current-user", {
          headers: {
            "Authorization": `Bearer ${localStorage.getItem("accessToken")}`
          }
        });

        if (!userResponse.ok) {
          throw new Error("Failed to fetch user data");
        }

        const userData = await userResponse.json();
        setCurrentUser(userData);

        // Get messages
        const messagesResponse = await fetch("https://localhost:7235/api/admin/messages", {
          headers: {
            "Authorization": `Bearer ${localStorage.getItem("accessToken")}`
          }
        });

        if (!messagesResponse.ok) {
          throw new Error("Failed to fetch messages");
        }

        const messagesData = await messagesResponse.json();
        setMessages(messagesData);
      } catch (error) {
        setError(error.message);
        if (error.message.includes("Unauthorized")) {
          try {
            await refreshToken();
            fetchData(); // Retry after token refresh
          } catch (refreshError) {
            setAuth(false);
            navigate("/login");
          }
        }
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, [auth, navigate, setAuth]);

  const refreshToken = async () => {
    const refreshToken = localStorage.getItem("refreshToken");
    if (!refreshToken) {
      throw new Error("No refresh token available");
    }

    const response = await fetch("https://localhost:7235/api/auth/refresh-token", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        accessToken: localStorage.getItem("accessToken"),
        refreshToken: refreshToken
      }),
    });

    if (!response.ok) {
      throw new Error("Token refresh failed");
    }

    const data = await response.json();
    localStorage.setItem("accessToken", data.accessToken);
    localStorage.setItem("refreshToken", data.refreshToken);
  };

  const handleLogout = async () => {
    try {
      await fetch("https://localhost:7235/api/auth/logout", {
        method: "POST",
        headers: {
          "Authorization": `Bearer ${localStorage.getItem("accessToken")}`
        }
      });

      localStorage.removeItem("accessToken");
      localStorage.removeItem("refreshToken");
      setAuth(false);
      navigate("/login");
    } catch (error) {
      console.error("Logout failed:", error);
    }
  };

  const toggleMessageSelection = (id) => {
    setSelectedMessages(prev =>
      prev.includes(id)
        ? prev.filter(messageId => messageId !== id)
        : [...prev, id]
    );
  };

  const markAsRead = async () => {
    if (selectedMessages.length === 0) return;

    try {
      const response = await fetch("https://localhost:7235/api/admin/messages/mark-as-read", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${localStorage.getItem("accessToken")}`
        },
        body: JSON.stringify({
          messageIds: selectedMessages
        }),
      });

      if (!response.ok) {
        throw new Error("Failed to mark messages as read");
      }

      // Update local state
      setMessages(prev =>
        prev.map(message =>
          selectedMessages.includes(message.id)
            ? { ...message, isRead: true }
            : message
        )
      );
      setSelectedMessages([]);
    } catch (error) {
      setError(error.message);
    }
  };

  const deleteSelected = async () => {
    if (selectedMessages.length === 0) return;

    try {
      const response = await fetch("https://localhost:7235/api/admin/messages/delete", {
        method: "DELETE",
        headers: {
          "Content-Type": "application/json",
          "Authorization": `Bearer ${localStorage.getItem("accessToken")}`
        },
        body: JSON.stringify({
          messageIds: selectedMessages
        }),
      });

      if (!response.ok) {
        throw new Error("Failed to delete messages");
      }

      // Update local state
      setMessages(prev =>
        prev.filter(message => !selectedMessages.includes(message.id))
      );
      setSelectedMessages([]);
    } catch (error) {
      setError(error.message);
    }
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleString();
  };

  const filteredMessages = messages.filter(message => {
    // Filter by read/unread status
    if (filter === "read" && !message.isRead) return false;
    if (filter === "unread" && message.isRead) return false;
    
    // Filter by search term
    if (searchTerm) {
      const searchLower = searchTerm.toLowerCase();
      return (
        message.fullName.toLowerCase().includes(searchLower) ||
        message.email.toLowerCase().includes(searchLower) ||
        message.subject.toLowerCase().includes(searchLower) ||
        message.message.toLowerCase().includes(searchLower)
      );
    }
    
    return true;
  });

  if (loading) {
    return (
      <div className="loading-container">
        <div className="spinner"></div>
        <p>Loading messages...</p>
      </div>
    );
  }

  return (
    <div className="admin-messages-container">
      <header className="admin-header">
        <div className="header-content">
          <h1>Messages Dashboard</h1>
          <div className="header-actions">
            <div className="user-info">
              <span className="username">{currentUser?.username}</span>
              <span className={`role ${currentUser?.role.toLowerCase()}`}>
                {currentUser?.role}
              </span>
            </div>
            <button className="btn logout-btn" onClick={handleLogout}>
              <i className="fas fa-sign-out-alt"></i> Logout
            </button>
          </div>
        </div>
      </header>

      <main className="messages-content">
        {error && <div className="alert error">{error}</div>}

        <div className="toolbar">
          <div className="search-filter">
            <div className="search-box">
              <i className="fas fa-search"></i>
              <input
                type="text"
                placeholder="Search messages..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <select 
              value={filter}
              onChange={(e) => setFilter(e.target.value)}
              className="filter-select"
            >
              <option value="all">All Messages</option>
              <option value="unread">Unread Only</option>
              <option value="read">Read Only</option>
            </select>
          </div>

          <div className="actions">
            <button 
              className={`btn action-btn ${selectedMessages.length === 0 ? 'disabled' : ''}`}
              onClick={markAsRead}
              disabled={selectedMessages.length === 0}
            >
              <i className="fas fa-check"></i> Mark as Read
            </button>
            <button 
              className={`btn action-btn danger ${selectedMessages.length === 0 ? 'disabled' : ''}`}
              onClick={deleteSelected}
              disabled={selectedMessages.length === 0}
            >
              <i className="fas fa-trash"></i> Delete
            </button>
            {currentUser?.role === "SuperAdmin" && (
              <button 
                className="btn action-btn primary"
                onClick={() => navigate("/admin/invite")}
              >
                <i className="fas fa-user-plus"></i> Invite Admin
              </button>
            )}
          </div>
        </div>

        <div className="messages-list">
          {filteredMessages.length === 0 ? (
            <div className="no-messages">
              <i className="fas fa-inbox"></i>
              <p>No messages found</p>
            </div>
          ) : (
            <div className="table-container">
              <table>
                <thead>
                  <tr>
                    <th className="checkbox-cell"></th>
                    <th>From</th>
                    <th>Email</th>
                    <th>Phone</th>
                    <th>Subject</th>
                    <th>Message</th>
                    <th>Date</th>
                    <th>Status</th>
                  </tr>
                </thead>
                <tbody>
                  {filteredMessages.map(message => (
                    <tr 
                      key={message.id} 
                      className={message.isRead ? "" : "unread"}
                      onClick={() => toggleMessageSelection(message.id)}
                    >
                      <td className="checkbox-cell">
                        <input
                          type="checkbox"
                          checked={selectedMessages.includes(message.id)}
                          onChange={() => toggleMessageSelection(message.id)}
                          onClick={e => e.stopPropagation()}
                        />
                      </td>
                      <td>{message.fullName}</td>
                      <td>
                        <a href={`mailto:${message.email}`} className="email-link">
                          {message.email}
                        </a>
                      </td>
                      <td>{message.phoneNumber || "-"}</td>
                      <td>{message.subject}</td>
                      <td className="message-preview">
                        {message.message.length > 50
                          ? `${message.message.substring(0, 50)}...`
                          : message.message}
                      </td>
                      <td>{formatDate(message.createdAt)}</td>
                      <td>
                        <span className={`status ${message.isRead ? 'read' : 'unread'}`}>
                          {message.isRead ? (
                            <>
                              <i className="fas fa-check-circle"></i> Read
                            </>
                          ) : (
                            <>
                              <i className="fas fa-envelope"></i> Unread
                            </>
                          )}
                        </span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default Messages;
